                        : "Blocks cross each other: block0=" +  block + ", block1= " + block0;
        }

        assert totalLen == len : "Summary length of blocks must be: " + len + " actual: " + totalLen;

        len -= 1024 * 2;
        start += 1024;
        maxLen -= igfs.context().data().groupBlockSize() * 2 / 1024;
    }
}

